import os
import shutil
import pandas as pd
import numpy as np
from fastapi import FastAPI, UploadFile, File, HTTPException, BackgroundTasks
from typing import List, Dict
import tensorflow as tf
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.applications import MobileNetV2
from tensorflow.keras.layers import Dense, GlobalAveragePooling2D
from tensorflow.keras.models import Model
from tensorflow.keras.optimizers import Adam
from sklearn.model_selection import train_test_split
from sklearn.preprocessing import LabelEncoder
import logging

# Configure logging
logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')

app = FastAPI()

# --- Configuration ---
DATA_DIR = "data"
IMAGES_DIR = os.path.join(DATA_DIR, "images")
LABELS_CSV_PATH = os.path.join(DATA_DIR, "labels.csv")
MODELS_DIR = "models"
CURRENT_MODEL_PATH = os.path.join(MODELS_DIR, "current_model")

# Ensure directories exist
os.makedirs(IMAGES_DIR, exist_ok=True)
os.makedirs(MODELS_DIR, exist_ok=True)

# Global variables for model and training status
current_model: tf.keras.Model = None
training_in_progress: bool = False
latest_accuracy: float = 0.0
num_classes: int = 0
label_encoder: LabelEncoder = None

# --- Helper Functions ---

def load_or_initialize_labels_csv() -> pd.DataFrame:
    """Loads existing labels.csv or initializes a new one."""
    if os.path.exists(LABELS_CSV_PATH):
        try:
            df = pd.read_csv(LABELS_CSV_PATH)
            logging.info(f"Loaded existing labels.csv with {len(df)} entries.")
            return df
        except Exception as e:
            logging.error(f"Error loading labels.csv: {e}. Initializing a new one.")
            return pd.DataFrame(columns=["filename", "label"])
    else:
        logging.info("labels.csv not found. Initializing a new one.")
        return pd.DataFrame(columns=["filename", "label"])

async def save_uploaded_data(image_files: List[UploadFile], labels_csv_file: UploadFile):
    """
    Saves uploaded image files and merges/appends new labels to the main labels.csv.
    """
    global LABELS_CSV_PATH

    # Save images
    new_image_filenames = []
    for image_file in image_files:
        filename = image_file.filename
        file_path = os.path.join(IMAGES_DIR, filename)
        try:
            with open(file_path, "wb") as f:
                shutil.copyfileobj(image_file.file, f)
            new_image_filenames.append(filename)
            logging.info(f"Saved image: {filename}")
        except Exception as e:
            logging.error(f"Failed to save image {filename}: {e}")
            # Optionally, remove from new_image_filenames if save failed

    if not new_image_filenames:
        raise HTTPException(status_code=400, detail="No images were successfully uploaded.")

    # Process labels CSV
    try:
        labels_df_new = pd.read_csv(labels_csv_file.file)
        if 'filename' not in labels_df_new.columns or 'label' not in labels_df_new.columns:
            raise ValueError("CSV must contain 'filename' and 'label' columns.")
        labels_df_new = labels_df_new[["filename", "label"]]
    except Exception as e:
        raise HTTPException(status_code=400, detail=f"Invalid labels CSV format: {e}")

    # Filter out labels for images not actually uploaded in this batch
    labels_df_new = labels_df_new[labels_df_new['filename'].isin(new_image_filenames)]

    if labels_df_new.empty:
        raise HTTPException(status_code=400, detail="No valid labels found in CSV corresponding to uploaded images.")

    # Load existing labels
    existing_labels_df = load_or_initialize_labels_csv()

    # Merge/append new labels, handling duplicates:
    # Prioritize new labels for existing filenames, otherwise append
    combined_labels_df = pd.concat([existing_labels_df, labels_df_new]).drop_duplicates(subset='filename', keep='last')

    # Save the combined DataFrame
    combined_labels_df.to_csv(LABELS_CSV_PATH, index=False)
    logging.info(f"Updated {LABELS_CSV_PATH} with {len(labels_df_new)} new entries. Total entries: {len(combined_labels_df)}")

def preprocess_image_for_prediction(image_path, target_size=(224, 224)):
    """Loads and preprocesses an image for the model prediction."""
    img = tf.keras.preprocessing.image.load_img(image_path, target_size=target_size)
    img_array = tf.keras.preprocessing.image.img_to_array(img)
    img_array = np.expand_dims(img_array, axis=0) # Add batch dimension
    return tf.keras.applications.mobilenet_v2.preprocess_input(img_array)

# --- ML Training Logic ---

def train_model_background_task():
    """
    Background task to train or fine-tune the image classification model.
    """
    global current_model, training_in_progress, latest_accuracy, num_classes, label_encoder

    if training_in_progress:
        logging.warning("Training already in progress. Skipping new request.")
        return

    training_in_progress = True
    logging.info("Starting model training...")

    try:
        # 1. Load Data
        df = load_or_initialize_labels_csv()
        if df.empty:
            logging.warning("No data available for training.")
            training_in_progress = False
            return

        # Filter out entries where the image file does not exist
        df['filepath'] = df['filename'].apply(lambda x: os.path.join(IMAGES_DIR, x))
        df = df[df['filepath'].apply(os.path.exists)]

        if df.empty:
            logging.warning("No valid image files found corresponding to labels for training.")
            training_in_progress = False
            return

        logging.info(f"Training with {len(df)} valid data points.")

        # Encode labels
        # Create a new LabelEncoder for each training run to ensure it's up-to-date
        current_label_encoder = LabelEncoder()
        df['encoded_label'] = current_label_encoder.fit_transform(df['label'])
        
        new_num_classes = len(current_label_encoder.classes_)
        logging.info(f"Detected {new_num_classes} unique classes: {current_label_encoder.classes_}")

        if new_num_classes < 2:
            logging.warning("Need at least 2 classes to train an image classification model.")
            training_in_progress = False
            return
        
        # Update global num_classes and label_encoder
        num_classes = new_num_classes
        label_encoder = current_label_encoder


        # Split data
        # Ensure enough samples per class for stratification, otherwise fall back to simple split
        if df['label'].value_counts().min() < 2:
            logging.warning("Not enough samples per class for stratification. Using simple train/test split.")
            train_df, val_df = train_test_split(df, test_size=0.2, random_state=42)
        else:
            train_df, val_df = train_test_split(df, test_size=0.2, random_state=42, stratify=df['label'])

        # Data Generators (using Keras ImageDataGenerator for convenience with dataframes)
        target_size = (224, 224)
        batch_size = 32

        train_datagen = ImageDataGenerator(
            preprocessing_function=tf.keras.applications.mobilenet_v2.preprocess_input,
            rotation_range=20,
            width_shift_range=0.2,
            height_shift_range=0.2,
            horizontal_flip=True,
            zoom_range=0.1
        )
        val_datagen = ImageDataGenerator(
            preprocessing_function=tf.keras.applications.mobilenet_v2.preprocess_input
        )

        train_generator = train_datagen.flow_from_dataframe(
            dataframe=train_df,
            x_col='filepath',
            y_col='label',
            target_size=target_size,
            batch_size=batch_size,
            class_mode='categorical', # Use 'categorical' for one-hot encoded labels
            shuffle=True
        )

        val_generator = val_datagen.flow_from_dataframe(
            dataframe=val_df,
            x_col='filepath',
            y_col='label',
            target_size=target_size,
            batch_size=batch_size,
            class_mode='categorical',
            shuffle=False
        )
        
        # Check if train_generator and val_generator were created successfully
        if train_generator.n == 0 or val_generator.n == 0:
            logging.warning("Not enough data to create valid training and/or validation generators. Skipping training.")
            training_in_progress = False
            return

        # 2. Build/Load Model
        model_to_train = None
        rebuild_top = False

        if current_model is None or not os.path.exists(CURRENT_MODEL_PATH):
            logging.info("No existing model found or loaded. Building a new MobileNetV2 based model.")
            rebuild_top = True
        else:
            logging.info(f"Loading existing model from {CURRENT_MODEL_PATH} for fine-tuning.")
            try:
                model_to_train = tf.keras.models.load_model(CURRENT_MODEL_PATH)
                if model_to_train.layers[-1].units != num_classes:
                    logging.warning(f"Existing model output layer has {model_to_train.layers[-1].units} units, but {num_classes} classes detected. Rebuilding top layers.")
                    rebuild_top = True
                else:
                    logging.info("Existing model loaded and output layer matches current number of classes.")
            except Exception as e:
                logging.error(f"Error loading existing model: {e}. Building a new model instead.")
                rebuild_top = True
        
        if rebuild_top:
            base_model = MobileNetV2(weights='imagenet', include_top=False, input_shape=(target_size[0], target_size[1], 3))
            base_model.trainable = False # Freeze base model initially

            x = base_model.output
            x = GlobalAveragePooling2D()(x)
            x = Dense(1024, activation='relu')(x)
            predictions = Dense(num_classes, activation='softmax')(x) # Output layer with num_classes

            model_to_train = Model(inputs=base_model.input, outputs=predictions)

        model_to_train.compile(optimizer=Adam(learning_rate=0.001),
                      loss='categorical_crossentropy',
                      metrics=['accuracy'])

        # 3. Train Model
        epochs = 10 # Can be adjusted or made configurable
        history = model_to_train.fit(
            train_generator,
            epochs=epochs,
            validation_data=val_generator,
            callbacks=[tf.keras.callbacks.EarlyStopping(patience=3, monitor='val_loss')]
        )

        latest_accuracy = history.history['val_accuracy'][-1] if 'val_accuracy' in history.history else history.history['accuracy'][-1]
        logging.info(f"Model training finished. Validation Accuracy: {latest_accuracy:.4f}")

        # 4. Save Model
        model_to_train.save(CURRENT_MODEL_PATH)
        current_model = model_to_train # Update the global model instance
        logging.info(f"Model saved to {CURRENT_MODEL_PATH}")

    except Exception as e:
        logging.error(f"Error during training: {e}", exc_info=True)
        latest_accuracy = 0.0 # Reset accuracy on error
        # Reset num_classes and label_encoder if training failed completely
        num_classes = 0
        label_encoder = None 

    finally:
        training_in_progress = False
        logging.info("Model training process concluded.")

# Load model and initialize label_encoder on startup if they exist
@app.on_event("startup")
async def startup_event():
    global current_model, num_classes, label_encoder
    if os.path.exists(CURRENT_MODEL_PATH):
        try:
            current_model = tf.keras.models.load_model(CURRENT_MODEL_PATH)
            logging.info("Existing model loaded successfully on startup.")
            num_classes = current_model.layers[-1].units

            # Attempt to initialize label_encoder from existing data
            df = load_or_initialize_labels_csv()
            if not df.empty:
                label_encoder = LabelEncoder()
                # Fit only on the 'label' column to get all known classes
                label_encoder.fit(df['label'].astype(str)) 
                logging.info(f"Initialized LabelEncoder with {len(label_encoder.classes_)} classes for prediction.")
            else:
                logging.warning("No labels.csv found on startup, LabelEncoder not initialized.")
        except Exception as e:
            logging.error(f"Error loading model or initializing LabelEncoder on startup: {e}")
            current_model = None
            label_encoder = None
            num_classes = 0

# --- FastAPI Endpoints ---

@app.get("/")
async def read_root():
    return {"message": "Welcome to the Community AI Training API!"}

@app.post("/upload_data")
async def upload_training_data(
    image_files: List[UploadFile] = File(..., description="List of image files to upload"),
    labels_csv: UploadFile = File(..., description="CSV file containing 'filename,label' for images")
) -> Dict[str, str]:
    """
    Uploads new training examples (images and their corresponding labels in a CSV).
    This data will be used to train/fine-tune the model.
    """
    if not image_files or not labels_csv:
        raise HTTPException(status_code=400, detail="Please upload at least one image file and a labels CSV.")

    try:
        await save_uploaded_data(image_files, labels_csv)
        return {"message": "Data uploaded and processed successfully. Trigger training to apply changes."}
    except HTTPException as e:
        raise e
    except Exception as e:
        logging.error(f"Error during data upload: {e}", exc_info=True)
        raise HTTPException(status_code=500, detail=f"Failed to process data: {str(e)}")

@app.post("/train")
async def trigger_training(background_tasks: BackgroundTasks) -> Dict[str, str]:
    """
    Triggers the model training process with all available data.
    Training runs in the background.
    """
    global training_in_progress
    if training_in_progress:
        raise HTTPException(status_code=409, detail="Training is already in progress.")

    # Check if there's enough data to train
    df = load_or_initialize_labels_csv()
    if df.empty or len(df['label'].unique()) < 2:
        raise HTTPException(status_code=400, detail="Not enough data or classes available to start training. Please upload more data.")

    background_tasks.add_task(train_model_background_task)
    return {"message": "Model training has been started in the background."}

@app.get("/status")
async def get_training_status() -> Dict[str, any]:
    """
    Gets the current status of the training process and the latest model accuracy.
    """
    return {
        "training_in_progress": training_in_progress,
        "latest_model_accuracy": f"{latest_accuracy:.4f}" if latest_accuracy else "N/A",
        "model_loaded": current_model is not None,
        "num_classes_in_model": num_classes if current_model else "N/A",
        "data_points_available": len(load_or_initialize_labels_csv()),
        "classes_known_by_encoder": label_encoder.classes_.tolist() if label_encoder is not None else []
    }

@app.post("/predict")
async def predict_image(image_file: UploadFile = File(...)) -> Dict[str, any]:
    """
    Makes a prediction on a single uploaded image using the current model.
    """
    if current_model is None:
        raise HTTPException(status_code=404, detail="Model not loaded. Please train a model first.")

    if training_in_progress:
        raise HTTPException(status_code=409, detail="Model is currently being trained. Please wait.")
    
    if label_encoder is None or num_classes == 0:
        raise HTTPException(status_code=500, detail="Label encoder not initialized or no classes known. Please train model first.")

    # Save temp image for prediction
    temp_image_path = os.path.join(DATA_DIR, f"temp_predict_image_{image_file.filename}")
    try:
        with open(temp_image_path, "wb") as f:
            shutil.copyfileobj(image_file.file, f)

        preprocessed_img = preprocess_image_for_prediction(temp_image_path)
        predictions = current_model.predict(preprocessed_img)
        predicted_class_index = np.argmax(predictions, axis=1)[0]
        confidence = float(predictions[0][predicted_class_index])

        if predicted_class_index >= len(label_encoder.classes_):
             raise HTTPException(status_code=500, detail="Predicted class index out of bounds for current label encoder. Model and encoder might be out of sync.")

        predicted_label = label_encoder.inverse_transform([predicted_class_index])[0]

        return {
            "predicted_label": predicted_label,
            "confidence": confidence,
            "all_predictions": {label: float(prob) for label, prob in zip(label_encoder.classes_, predictions[0])}
        }
    except Exception as e:
        logging.error(f"Error during prediction: {e}", exc_info=True)
        raise HTTPException(status_code=500, detail=f"Prediction failed: {str(e)}")
    finally:
        if os.path.exists(temp_image_path):
            os.remove(temp_image_path)

